INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.14.156','cb','cb.adi.14','ЧБ Ади 14.156',156,'হেনমতে প্রভু বঙ্গদেশ ধন্য করি’ ।
নিজ-গৃহে আইলেন গৌরাঙ্গ শ্রীহরি ॥১৫৬॥','хӣна-мате прабху бан̇га-деш́а дханйа кари’
ниджа-гр̣хе а̄илена гаура̄н̇га ш́рӣ-хари',NULL,NULL),('cb.adi.14.157','cb','cb.adi.14','ЧБ Ади 14.157',157,'ব্যবহারে অর্থ-বৃত্তি অনেক লইয়া ।
সন্ধ্যাকালে গৃহে প্রভু উত্তরিলা গিয়া ॥১৫৭॥','вйаваха̄ре артха-вр̣тти анека лаийа̄
сандхйа̄-ка̄ле гр̣хе прабху уттарила̄ гийа̄',NULL,NULL),('cb.adi.14.158','cb','cb.adi.14','ЧБ Ади 14.158',158,'দবৎ কৈলা প্রভু জননী-চরণে ।
অর্থ-বৃত্তি সকল দিলেন তান স্থানে ॥১৫৮॥','дан̣д̣ават каила̄ прабху джананӣ-чаран̣е
артха-вр̣тти сакала дилена та̄’на стха̄не',NULL,NULL),('cb.adi.14.159','cb','cb.adi.14','ЧБ Ади 14.159',159,'সেইক্ষণে প্রভু শিষ্যগণের সহিতে ।
চলিলেন শীঘ্র গঙ্গা-মজ্জন করিতে ॥১৫৯॥','сеи-кш̣ан̣е прабху ш́иш̣йа-ган̣ера сахите
чалилена ш́ӣгхра ган̇га̄-маджджана карите',NULL,NULL),('cb.adi.14.160','cb','cb.adi.14','ЧБ Ади 14.160',160,'সেইক্ষণে গেলা আই করিতে রন্ধন ।
অন্তরে দুঃখিতা, লঞা সর্ব্ব-পরিজন ॥১৬০॥','сеи-кш̣ан̣е гела̄ а̄и карите рандхана
антаре дух̣кхита̄, лан̃а̄ сарва-париджана',NULL,NULL),('cb.adi.14.161','cb','cb.adi.14','ЧБ Ади 14.161',161,'শিক্ষাগুরু প্রভু সর্ব্বগণের সহিতে ।
গঙ্গারে হইলা দবৎ বহুমতে ॥১৬১॥','ш́икш̣а̄-гуру прабху сарва-ган̣ера сахите
ган̇га̄ре хаила̄ дан̣д̣ават баху-мате',NULL,NULL),('cb.adi.14.162','cb','cb.adi.14','ЧБ Ади 14.162',162,'কতক্ষণ জাহ্নবীতে করি’ জলখেলা ।
স্নান করি’ গঙ্গা দেখি’ গৃহেতে আইলা ॥১৬২॥','ката-кш̣ан̣а джа̄хнавӣте кари’ джала-кхела̄
сна̄на кари’ ган̇га̄ декхи’ гр̣хете а̄ила̄',NULL,NULL),('cb.adi.14.163','cb','cb.adi.14','ЧБ Ади 14.163',163,'তবে প্রভু যথোচিত নিত্যকর্ম্ম করি’ ।
ভোজনে বসিলা গিয়া গৌরাঙ্গ শ্রীহরি ॥১৬৩॥','бходжане васила̄ гийа̄ гаура̄н̇га ш́рӣ-хари',NULL,NULL),('cb.adi.14.164','cb','cb.adi.14','ЧБ Ади 14.164',164,'সন্তোষে বৈকুণ্ঠনাথ ভোজন করিয়া ।
বিষ্ণুগৃহদ্বারে প্রভু বসিলা আসিয়া ॥১৬৪॥','сантош̣е ваикун̣т̣ха-на̄тха бходжана карийа̄
виш̣н̣у-гр̣ха-два̄ре прабху васила̄ а̄сийа̄',NULL,NULL),('cb.adi.14.165','cb','cb.adi.14','ЧБ Ади 14.165',165,'তবে আপ্তবর্গ আইলেন সম্ভাষিতে ।
সবেই বেড়িয়া বসিলেন চারিভিতে ॥১৬৫॥','табе а̄пта-варга а̄илена самбха̄ш̣ите
сабеи вед̣ийа̄ василена ча̄ри-бхите',NULL,NULL),('cb.adi.14.166','cb','cb.adi.14','ЧБ Ади 14.166',166,'সবার সহিত প্রভু হাস্য-কথা-রঙ্গে ।
কহিলেন যেমত আছিলা বঙ্গে রঙ্গে ॥১৬৬॥','саба̄ра сахита прабху ха̄сйа-катха̄-ран̇ге
кахилена йе-мата а̄чхила̄ бан̇ге ран̇ге',NULL,NULL),('cb.adi.14.167','cb','cb.adi.14','ЧБ Ади 14.167',167,'বঙ্গদেশী-বাক্য অনুকরণ করিয়া ।
বাঙ্গালেরে কদর্থেন হাসিয়া-হাসিয়া ॥১৬৭॥','бан̇га-деш́ӣ-ва̄кйа анукаран̣а карийа̄
ба̄н̇га̄лере кадартхена ха̄сийа̄ ха̄сийа̄',NULL,NULL),('cb.adi.14.168','cb','cb.adi.14','ЧБ Ади 14.168',168,'দুঃখরস হইবেক জানি’ আপ্তগণ ।
লক্ষ্মীর বিজয় কেহ না করে কথন ॥১৬৮॥','дух̣кха-раса хаибека джа̄ни а̄пта-ган̣а
лакш̣мӣра виджайа кеха на̄ каре катхана',NULL,NULL),('cb.adi.14.169','cb','cb.adi.14','ЧБ Ади 14.169',169,'কতক্ষণ থাকিয়া সকল আপ্তগণ ।
বিদায় হইয়া গেল, যার যে ভবন ॥১৬৯॥','ката-кш̣ан̣а тха̄кийа̄ сакала а̄пта-ган̣а
вида̄йа хаийа̄ гела, йа̄’ра йе бхавана',NULL,NULL),('cb.adi.14.170','cb','cb.adi.14','ЧБ Ади 14.170',170,'বসিয়া করেন প্রভু তাম্বূল চর্ব্বণ ।
নানা-হাস্য-পরিহাস করেন কথন ॥১৭০॥','васийа̄ карена прабху та̄мбӯла чарван̣а
на̄на̄-ха̄сйа-париха̄са карена катхана',NULL,NULL),('cb.adi.14.171','cb','cb.adi.14','ЧБ Ади 14.171',171,'শচী-দেবী অন্তরে দুঃখিতা হই’ ঘরে ।
কাছে না আইসেন পুত্ত্রের গোচরে ॥১৭১॥','ш́ачӣ-девӣ антаре дух̣кхита̄ хаи’ гхаре
ка̄чхе на̄-а̄исена путрера гочаре',NULL,NULL),('cb.adi.14.172','cb','cb.adi.14','ЧБ Ади 14.172',172,'আপনি চলিলা প্রভু জননী-সম্মুখে ।
দুঃখিত-বদনা প্রভু জননীরে দেখে ॥১৭২॥','а̄пани чалила̄ прабху джананӣ-саммукхе
дух̣кхита-вадана̄ прабху джананӣре декхе',NULL,NULL),('cb.adi.14.173','cb','cb.adi.14','ЧБ Ади 14.173',173,'জননীরে বলে প্রভু মধুর বচন ।
“দুঃখিতা তোমারে, মাতা, দেখি কি-কারণ? ॥১৭৩॥','джананӣре бале прабху мадхура вачана
‘дух̣кхита̄ тома̄ре, ма̄та̄, декхи ки-ка̄ран̣а?',NULL,NULL),('cb.adi.14.174','cb','cb.adi.14','ЧБ Ади 14.174',174,'কুশলে আইনু আমি দূর-দেশ হৈতে ।
কোথা তুমি মঙ্গল করিবা ভাল-মতে ॥১৭৪॥','куш́але а̄ину а̄ми дӯра-деш́а хаите
котха̄ туми ман̇гала кариба̄ бха̄ла-мате',NULL,NULL),('cb.adi.14.175','cb','cb.adi.14','ЧБ Ади 14.175',175,'আর তোমা’ দেখি অতি-দুঃখিত-বদন ।
সত্য কহ দেখি, মাতা, ইহার কারণ?” ॥১৭৫॥','а̄ра тома̄’ декхи ати-дух̣кхита-вадана
сатйа каха декхи, ма̄та̄, иха̄ра ка̄ран̣а?’',NULL,NULL),('cb.adi.14.176','cb','cb.adi.14','ЧБ Ади 14.176',176,'শুনিয়া পুত্ত্রের বাক্য আই অধোমুখে ।
কান্দে মাত্র, উত্তর না করে কিছু দুঃখে ॥১৭৬॥','ш́унийа̄ путрера ва̄кйа а̄и адхо-мукхе
ка̄нде ма̄тра, уттара на̄ каре кичху дух̣кхе',NULL,NULL),('cb.adi.14.177','cb','cb.adi.14','ЧБ Ади 14.177',177,'প্রভু বোলে,—“মাতা, আমি জানিনু সকল ।
তোমার বধূর কিছু বুঝি অমঙ্গল?” ॥১৭৭॥','прабху бале, — ‘ма̄та̄, а̄ми джа̄нину сакала
тома̄ра вадхура кичху буджхи аман̇гала?’',NULL,NULL),('cb.adi.14.178','cb','cb.adi.14','ЧБ Ади 14.178',178,'তবে সবে কহিলেন,—“শুনহ, পণ্ডিত! ।
তোমার ব্রাহ্মণী গঙ্গা পাইলা নিশ্চিত” ॥১৭৮॥','табе сабе кахилена, — ‘ш́унаха, пан̣д̣ита!
тома̄ра бра̄хман̣ӣ ган̇га̄ па̄ила̄ ниш́чита',NULL,NULL),('cb.adi.14.179','cb','cb.adi.14','ЧБ Ади 14.179',179,'পত্নীর বিজয় শুনি’ গৌরাঙ্গ শ্রীহরি ।
ক্ষণেক রহিলা প্রভু হেঁট মাথা করি’ ॥১৭৯॥','патнӣра виджайа ш́уни’ гаура̄н̇га ш́рӣ-хари
кш̣ан̣ека рахила̄ прабху хен̇т̣а ма̄тха̄ кари’',NULL,NULL),('cb.adi.14.180','cb','cb.adi.14','ЧБ Ади 14.180',180,'প্রিয়ার বিরহ-দুঃখ করিয়া স্বীকার ।
তুষ্ণী হই’ রহিলেন সর্ব্ব-বেদ-সার ॥১৮০॥','прийа̄ра вираха-дух̣кха карийа̄ свӣка̄ра
тӯш̣н̣е хаи’ рахилена сарва-веда-са̄ра',NULL,NULL),('cb.adi.14.181','cb','cb.adi.14','ЧБ Ади 14.181',181,'লোকানুকরণ-দুঃখ ক্ষণেক করিয়া ।
কহিতে লাগিলা নিজে ধীর-চিত্ত হৈয়া ॥১৮১॥','лока̄нукаран̣а-дух̣кха кш̣анека карийа̄
кахите ла̄гила̄ нидже дхӣра-читта хаийа̄',NULL,NULL),('cb.adi.14.182','cb','cb.adi.14','ЧБ Ади 14.182',182,'কস্য কে পতিপুত্ত্রাদ্যা মোহ এব হি কারণম্ ॥১৮২॥','касйа ке пати-путра̄дйа̄ моха эва хи ка̄ран̣ам',NULL,NULL),('cb.adi.14.183','cb','cb.adi.14','ЧБ Ади 14.183',183,'প্রভু বলে,—“মাতা, দুঃখ ভাব’ কি-কারণে? ।
ভবিতব্য যে আছে, সে খণ্ডিবে কেমনে? ॥১৮৩॥','прабху бале, — ‘ма̄та̄, дух̣кха бха̄ва’ ки-ка̄ран̣е?
бхавитавйа йе а̄чхе, се кхан̣д̣ибе кемане?',NULL,NULL),('cb.adi.14.186','cb','cb.adi.14','ЧБ Ади 14.186',186,'অতএব যে হইল ঈশ্বর-ইচ্ছায় ।
হইল সে কার্য্য, আর দুঃখ কেনে তায়? ॥১৮৬॥','атаева йе хаила ӣш́вара-иччха̄йа
хаила се ка̄рйа, а̄ра дух̣кха кене та̄йа?',NULL,NULL),('cb.adi.14.187','cb','cb.adi.14','ЧБ Ади 14.187',187,'স্বামীর অগ্রেতে গঙ্গা পায় যে সুকৃতি ।
তার বড় আর কে বা আছে ভাগ্যবতী?” ॥১৮৭॥','сва̄мӣра агрете ган̇га̄ па̄йа йе сукр̣ти
та̄’ра бад̣а а̄ра ке ва̄ а̄чхе бха̄гйаватӣ?’',NULL,NULL),('cb.adi.14.188','cb','cb.adi.14','ЧБ Ади 14.188',188,'এইমত প্রভু জননীরে প্রবোধিয়া ।
রহিলেন নিজ-কৃত্যে আপ্তগণ লৈয়া ॥১৮৮॥','эи-мата прабху джананӣре прабодхийа̄
рахилена ниджа-кр̣тйе а̄пта-ган̣а лаийа̄',NULL,NULL),('cb.adi.14.189','cb','cb.adi.14','ЧБ Ади 14.189',189,'শুনিয়া প্রভুর অতি অমৃত-বচন ।
সবার হইল সর্ব্বদুঃখ-বিমোচন ॥১৮৯॥','ш́унийа̄ прабхура ати амр̣та-вачана
саба̄ра хаила сарва-дух̣кха-вимочана',NULL,NULL),('cb.adi.14.190','cb','cb.adi.14','ЧБ Ади 14.190',190,'হেনমতে বৈকুণ্ঠ-নায়ক গৌরহরি ।
কৌতুকে আছেন বিদ্যা-রসে ক্রীড়া করি’ ॥১৯০॥','хӣна мате ваикун̣т̣ха-на̄йака гаурахари
каутуке а̄чхена видйа̄-расе крӣд̣а̄ кари’',NULL,NULL),('cb.adi.14.191','cb','cb.adi.14','ЧБ Ади 14.191',191,'শ্রীকৃষ্ণচৈতন্য-নিত্যানন্দচান্দ জান ।
বৃন্দাবনদাস তছু পদযুগে গান ॥১৯১॥','ш́рӣ кр̣ш̣н̣а-чаитанйа нитйа̄нанда-ча̄нда джа̄на
вр̣нда̄вана да̄са тачху пада-йуге га̄на',NULL,NULL),('cb.adi.15.1','cb','cb.adi.15','ЧБ Ади 15.1',1,'জয় জয় গৌরচন্দ্র জয় নিত্যানন্দ ।
দান দেহ’ হৃদয়ে তোমার পদদ্বন্দ্ব ॥১॥','джайа джайа гаурачандра джайа нитйа̄нанда
да̄на деха’ хр̣дайе тома̄ра пада-двандва',NULL,NULL),('cb.adi.15.2','cb','cb.adi.15','ЧБ Ади 15.2',2,'গোষ্ঠীর সহিতে গৌরাঙ্গ জয় জয় ।
শুনিলে চৈতন্য-কথা ভক্তি লভ্য হয় ॥২॥','гош̣т̣хӣра сахите гаура̄н̇га джайа-джайа
ш́униле чаитанйа-катха̄ бхакти лабхйа хайа',NULL,NULL),('cb.adi.15.3','cb','cb.adi.15','ЧБ Ади 15.3',3,'হেনমতে মহাপ্রভু বিদ্যার আবেশে ।
আছে গূঢ়রূপে, কারে না করে প্রকাশে ॥৩॥','хӣна-мате маха̄прабху видйа̄ра а̄веш́е
а̄чхе гӯд̣ха-рӯпе, ка̄’ре на̄ каре прака̄ш́е',NULL,NULL),('cb.adi.15.4','cb','cb.adi.15','ЧБ Ади 15.4',4,'সন্ধ্যা-বন্দনাদি প্রভু করি’ ঊষঃকালে ।
নমস্করি’ জননীরে পড়াইতে চলে ॥৪॥','сандхйа̄-вандана̄ди прабху кари’ ӯш̣ах̣-ка̄ле
намаскари’ джананӣре пад̣а̄ите чале',NULL,NULL),('cb.adi.15.5','cb','cb.adi.15','ЧБ Ади 15.5',5,'অনেক জন্মের ভৃত্য মুকুন্দ-সঞ্জয় ।
পুরুষোত্তমদাস হয় যাঁহার তনয় ॥৫॥','анека джанмера бхр̣тйа мукунда-сан̃джайа
пуруш̣оттама-да̄са хайа йа̄н̇ха̄ра танайа',NULL,NULL),('cb.adi.15.6','cb','cb.adi.15','ЧБ Ади 15.6',6,'প্রতিদিন সেই ভাগ্যবন্তের আলয় ।
পড়াইতে গৌরচন্দ্র করেন বিজয় ॥৬॥','прати-дина сеи бха̄гйавантера а̄лайа
